import { useState, useEffect, useRef } from "react";

const API = "https://mantl-api-2.onrender.com";

const FALLBACK = [
  { artist:"Zdzislaw Beksinski", h:320, bg:"linear-gradient(135deg,#1a0808,#3a1010,#0a0404)", title:"Untitled", year:"1984" },
  { artist:"Moebius", h:255, bg:"linear-gradient(160deg,#080e14,#1a2a3a,#04080c)", title:"Arzach", year:"1975" },
  { artist:"HR Giger", h:295, bg:"linear-gradient(135deg,#06060e,#1a1a30,#06060e)", title:"Necronomicon IV", year:"1976" },
  { artist:"Chris Foss", h:360, bg:"linear-gradient(180deg,#2a1808,#5a2810,#0a0400)", title:"Spacecraft", year:"1980" },
  { artist:"Ernst Haeckel", h:300, bg:"linear-gradient(145deg,#0c0c04,#2a3010,#141408)", title:"Radiolaria", year:"1904" },
  { artist:"Francis Bacon", h:265, bg:"linear-gradient(200deg,#1a0404,#4a1008,#0a0404)", title:"Study After Velazquez", year:"1953" },
  { artist:"Remedios Varo", h:340, bg:"linear-gradient(180deg,#201a10,#100c08,#181410)", title:"Embroidering the Earth", year:"1961" },
  { artist:"Roger Dean", h:225, bg:"linear-gradient(90deg,#060a08,#102a1a,#060604)", title:"Fragile", year:"1972" },
  { artist:"Leonora Carrington", h:390, bg:"linear-gradient(170deg,#180c04,#4a2810,#0c0804)", title:"The Giantess", year:"1947" },
  { artist:"Max Ernst", h:275, bg:"linear-gradient(150deg,#100410,#281028,#060206)", title:"The Robing of the Bride", year:"1940" },
  { artist:"Wayne Barlowe", h:315, bg:"linear-gradient(200deg,#181010,#301408,#0a0404)", title:"Expedition", year:"1990" },
  { artist:"Andrei Tarkovsky", h:250, bg:"linear-gradient(90deg,#0c0804,#30200c,#060402)", title:"Stalker", year:"1979" },
  { artist:"Hieronymus Bosch", h:300, bg:"linear-gradient(135deg,#0c140c,#041004,#1a2410)", title:"Garden of Earthly Delights", year:"1503" },
  { artist:"Gustave Moreau", h:355, bg:"linear-gradient(120deg,#1a1004,#3a2808,#0a0804)", title:"Jupiter and Semele", year:"1894" },
  { artist:"Ivan Bilibin", h:235, bg:"linear-gradient(200deg,#080818,#101838,#040408)", title:"Baba Yaga", year:"1902" },
  { artist:"Austin Osman Spare", h:305, bg:"linear-gradient(160deg,#140c0c,#2a1414,#080404)", title:"Portrait of a Witch", year:"1920" },
];

const LOGO = "data:image/png;base64,";

function Lightbox({ item, onClose }) {
  useEffect(() => {
    const handler = e => { if (e.key === "Escape") onClose(); };
    window.addEventListener("keydown", handler);
    document.body.style.overflow = "hidden";
    return () => {
      window.removeEventListener("keydown", handler);
      document.body.style.overflow = "";
    };
  }, [onClose]);

  return (
    <div
      onClick={onClose}
      style={{
        position: "fixed", inset: 0, background: "rgba(10,8,8,0.97)",
        zIndex: 9999, display: "flex", flexDirection: "column",
        alignItems: "center", justifyContent: "center",
        cursor: "zoom-out", padding: "20px 16px",
      }}
    >
      <div
        onClick={e => e.stopPropagation()}
        style={{ display: "flex", flexDirection: "column", alignItems: "center", maxWidth: 680, width: "100%" }}
      >
        {/* Image */}
        <div style={{ width: "100%", marginBottom: 16 }}>
          {item.image_url ? (
            <img src={item.image_url} alt={item.artist}
              style={{ maxWidth: "100%", maxHeight: "65vh", objectFit: "contain", display: "block", margin: "0 auto" }} />
          ) : (
            <div style={{ width: "100%", height: 300, background: item.bg }} />
          )}
        </div>

        {/* Details — always visible */}
        <div style={{
          width: "100%", borderLeft: "3px solid #2060e0", paddingLeft: 16,
          borderBottom: "1px solid #1e1c1a", paddingBottom: 16,
        }}>
          <div style={{ fontFamily: "'Anton', sans-serif", fontSize: "clamp(14px, 3vw, 20px)", textTransform: "uppercase", letterSpacing: 2, color: "#e0dcd6", marginBottom: 4 }}>
            {item.artist || "Unknown Artist"}
          </div>
          {item.title && item.title !== "unknown" && (
            <div style={{ fontSize: 12, color: "#8a6830", fontStyle: "italic", marginBottom: 3 }}>{item.title}</div>
          )}
          {item.year && item.year !== "unknown" && (
            <div style={{ fontSize: 10, color: "#4a4540", letterSpacing: 1 }}>{item.year}</div>
          )}
          {item.source_url && (
            <a href={item.source_url} target="_blank" rel="noreferrer"
              onClick={e => e.stopPropagation()}
              style={{ fontSize: 9, color: "#2060e0", letterSpacing: 2, textTransform: "uppercase", marginTop: 10, display: "inline-block" }}>
              Source →
            </a>
          )}
        </div>

        <div style={{ marginTop: 16, fontSize: 9, color: "#4a4540", letterSpacing: 2, textTransform: "uppercase" }}>
          tap anywhere to close
        </div>
      </div>
    </div>
  );
}

function WallCard({ item, onClick }) {
  const [hov, setHov] = useState(false);
  return (
    <div
      onClick={onClick}
      onMouseEnter={() => setHov(true)}
      onMouseLeave={() => setHov(false)}
      onTouchStart={() => setHov(true)}
      onTouchEnd={() => setHov(false)}
      style={{
        position: "relative", overflow: "hidden", cursor: "zoom-in",
        background: item.image_url ? "#0a0808" : (item.bg || "#141110"),
        width: "100%", paddingBottom: "130%",
      }}
    >
      <div style={{ position: "absolute", bottom: 0, left: 0, right: 0, height: 3, background: "#2060e0", zIndex: 2 }} />
      {item.image_url ? (
        <img src={item.image_url} alt={item.artist}
          style={{
            position: "absolute", inset: 0, width: "100%", height: "100%", objectFit: "cover",
            transform: hov ? "scale(1.04)" : "scale(1)",
            transition: "transform 0.5s cubic-bezier(.16,1,.3,1)",
          }} />
      ) : (
        <div style={{ position: "absolute", inset: 0, background: item.bg }} />
      )}
      <div style={{
        position: "absolute", bottom: 3, left: 0, right: 0,
        padding: "24px 14px 12px",
        background: "linear-gradient(to top, rgba(10,8,8,0.95) 0%, transparent 100%)",
        opacity: hov ? 1 : 0, transition: "opacity 0.25s ease", zIndex: 3,
      }}>
        <div style={{ fontFamily: "'Anton', sans-serif", fontSize: 11, textTransform: "uppercase", letterSpacing: 2, color: "#e0dcd6" }}>
          {item.artist || item.artist_name || "Unknown"}
        </div>
        {item.year && <div style={{ fontFamily: "'Courier Prime', monospace", fontSize: 9, color: "#8a6830", letterSpacing: 2, marginTop: 2 }}>{item.year}</div>}
      </div>
    </div>
  );
}

export default function App() {
  const [stats, setStats] = useState({ artists: 0, works: 0 });
  const [wall, setWall] = useState(FALLBACK);
  const [allWall, setAllWall] = useState([]);
  const [search, setSearch] = useState("");
  const [lightbox, setLightbox] = useState(null);
  const inputRef = useRef();

  useEffect(() => {
    const warm = setInterval(() => { fetch(API + "/api/stats").catch(() => {}); }, 9 * 60 * 1000);
    fetch(API + "/api/stats").then(r => r.json()).then(d => setStats({ artists: d.artists, works: d.works })).catch(() => {});
    fetch(API + "/api/works?limit=200")
      .then(r => r.json())
      .then(data => {
        if (Array.isArray(data) && data.length > 0) {
          setAllWall(data);
          setWall(data);
        }
      })
      .catch(() => {});
    return () => clearInterval(warm);
  }, []);

  const handleSearch = val => {
    setSearch(val);
    if (!val.trim()) { setWall(allWall); return; }
    const q = val.toLowerCase();
    setWall(allWall.filter(item =>
      (item.artist && item.artist.toLowerCase().includes(q)) ||
      (item.title && item.title.toLowerCase().includes(q)) ||
      (item.year && item.year.includes(q))
    ));
  };

  return (
    <div style={{ background: "#0a0808", minHeight: "100vh", color: "#e0dcd6", fontFamily: "'Courier Prime', monospace" }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Anton&family=Courier+Prime:wght@400;700&display=swap');
        * { margin: 0; padding: 0; box-sizing: border-box; }
        body { background: #0a0808; }
        .wall { display: grid; grid-template-columns: repeat(3, 1fr); gap: 3px; width: 100%; }
        @media(max-width: 600px) { .wall { grid-template-columns: repeat(2, 1fr); } }
        input::placeholder { color: #4a4540; }
        input:focus { outline: none; border-color: #2060e0 !important; }
      `}</style>

      {lightbox && <Lightbox item={lightbox} onClose={() => setLightbox(null)} />}

      {/* HEADER */}
      <div style={{ display: "flex", flexDirection: "column", alignItems: "center", padding: "28px 24px 20px", borderBottom: "1px solid #1e1c1a" }}>
        <img src={LOGO} alt="MANTL" style={{ height: "clamp(44px, 7vw, 72px)", width: "auto", marginBottom: 18 }} />

        {/* Search */}
        <div style={{ position: "relative", width: "100%", maxWidth: 480, marginBottom: 18 }}>
          <svg viewBox="0 0 24 24" style={{ position: "absolute", left: 12, top: "50%", transform: "translateY(-50%)", width: 12, height: 12, stroke: "#4a4540", fill: "none", strokeWidth: 2, pointerEvents: "none" }}>
            <circle cx="11" cy="11" r="7"/><line x1="16.5" y1="16.5" x2="21" y2="21"/>
          </svg>
          <input
            ref={inputRef}
            type="text"
            placeholder="Search artist, title, year..."
            value={search}
            onChange={e => handleSearch(e.target.value)}
            style={{
              width: "100%", background: "#141110", border: "1px solid #2a2725",
              color: "#e0dcd6", fontFamily: "'Courier Prime', monospace",
              fontSize: 11, letterSpacing: 1, padding: "9px 14px 9px 34px",
              transition: "border-color 0.2s",
            }}
          />
          {search && (
            <span onClick={() => handleSearch("")}
              style={{ position: "absolute", right: 12, top: "50%", transform: "translateY(-50%)", cursor: "pointer", color: "#4a4540", fontSize: 14 }}>
              ×
            </span>
          )}
        </div>

        {/* Stats */}
        <div style={{ display: "flex", gap: "clamp(20px, 4vw, 48px)", alignItems: "center" }}>
          <div style={{ textAlign: "center" }}>
            <div style={{ fontSize: "clamp(18px, 2.5vw, 24px)", fontWeight: 700, color: "#e0dcd6", lineHeight: 1 }}>{stats.works.toLocaleString()}</div>
            <div style={{ fontSize: 9, color: "#8a6830", letterSpacing: 3, textTransform: "uppercase", marginTop: 4 }}>works</div>
          </div>
          <div style={{ width: 1, height: 24, background: "#2060e0" }} />
          <div style={{ textAlign: "center" }}>
            <div style={{ fontSize: "clamp(18px, 2.5vw, 24px)", fontWeight: 700, color: "#e0dcd6", lineHeight: 1 }}>{stats.artists.toLocaleString()}</div>
            <div style={{ fontSize: 9, color: "#8a6830", letterSpacing: 3, textTransform: "uppercase", marginTop: 4 }}>artists</div>
          </div>
          {search && (
            <>
              <div style={{ width: 1, height: 24, background: "#2a2725" }} />
              <div style={{ textAlign: "center" }}>
                <div style={{ fontSize: "clamp(18px, 2.5vw, 24px)", fontWeight: 700, color: "#2060e0", lineHeight: 1 }}>{wall.length}</div>
                <div style={{ fontSize: 9, color: "#4a4540", letterSpacing: 3, textTransform: "uppercase", marginTop: 4 }}>results</div>
              </div>
            </>
          )}
        </div>
      </div>

      {/* WALL */}
      <div className="wall">
        {wall.map((item, i) => (
          <WallCard key={i} item={item} onClick={() => setLightbox(item)} />
        ))}
        {wall.length === 0 && (
          <div style={{ gridColumn: "1/-1", textAlign: "center", padding: "80px 24px", color: "#4a4540", fontSize: 12, letterSpacing: 2, textTransform: "uppercase" }}>
            No results for "{search}"
          </div>
        )}
      </div>

    </div>
  );
}
